features.snippet:
input [63:0] clkin_data;
reg [5:0] q;
always_ff @(posedge clkin_data[0])
  q <= q + 1;

input [63:0] clkin_data;
reg [5:0] q;
always_ff @(posedge clkin_data[0], negedge clkin_data[32])
  if (!clkin_data[32]) q <= 6'h00;
  else q <= q + 1;

input [63:0] clkin_data;
wire clk = clkin_data[0];
wire rst = clkin_data[32];
reg [5:0] q;
always_ff @(posedge clk)
  if (!rst) q <= 6'h00;
  else q <= q + 1;

input [63:0] clkin_data;
input [2:0] d;
reg [2:0] q;
always_latch
  if (!clkin_data[32]) q = 3'h0;
  else q = d;
